import React, { useState, useEffect } from 'react';
import { X, Plane, Calendar, Users, Briefcase } from 'lucide-react';
import { UserPreferences } from '../types';
import { AIRPORT_MAPPING } from '../constants';

interface Props {
  preferences: UserPreferences;
  onClose: () => void;
}

const FlightBookingModal: React.FC<Props> = ({ preferences, onClose }) => {
  // Extract initial destination/origin from preferences
  // Take first item if multiple destinations
  const initialDest = preferences.destination.split(',')[0].trim();
  const initialOrigin = preferences.departFrom || '';

  const [origin, setOrigin] = useState(initialOrigin);
  const [destination, setDestination] = useState(initialDest);

  // Codes
  const [originCode, setOriginCode] = useState('');
  const [destCode, setDestCode] = useState('');

  // Dates
  const [departDate, setDepartDate] = useState('');
  const [returnDate, setReturnDate] = useState('');

  // Passengers
  const [adults, setAdults] = useState(1);
  const [children, setChildren] = useState(0);
  const [cabinClass, setCabinClass] = useState('economy');

  // Auto-resolve codes on mount or when text changes
  useEffect(() => {
    resolveCode(origin, setOriginCode);
  }, [origin]);

  useEffect(() => {
    resolveCode(destination, setDestCode);
  }, [destination]);

  const resolveCode = (place: string, setCode: (code: string) => void) => {
    if (!place) return;
    const lower = place.toLowerCase().trim();
    // 1. Direct match in mapping
    if (AIRPORT_MAPPING[lower]) {
        setCode(AIRPORT_MAPPING[lower]);
        return;
    }
    // 2. Partial match check (e.g. "tokyo, japan" -> matches "tokyo")
    const keyMatch = Object.keys(AIRPORT_MAPPING).find(k => lower.includes(k));
    if (keyMatch) {
        setCode(AIRPORT_MAPPING[keyMatch]);
        return;
    }
    // 3. Fallback: If input looks like a code (3 letters), use it
    if (lower.length === 3) {
        setCode(lower.toUpperCase());
    }
  };

  // Convert YYYY-MM-DD to YYMMDD
  const formatSkyscannerDate = (isoDate: string): string => {
      if (!isoDate) return '';
      const [year, month, day] = isoDate.split('-');
      if (!year || !month || !day) return '';
      return `${year.slice(2)}${month}${day}`; // 2026-03-02 -> 260302
  };

  const handleSearch = () => {
      if (!originCode || !destCode || !departDate || !returnDate) {
          alert("Please fill in all required fields (Origin Code, Destination Code, Dates).");
          return;
      }

      const dep = formatSkyscannerDate(departDate);
      const ret = formatSkyscannerDate(returnDate);

      // Base URL Construction
      // https://www.skyscanner.com.my/transport/flights/kulm/hnd/260302/260308/?...
      const baseUrl = `https://www.skyscanner.com.my/transport/flights/${originCode.toLowerCase()}/${destCode.toLowerCase()}/${dep}/${ret}/`;

      const params = new URLSearchParams();
      params.append('adultsv2', adults.toString());
      params.append('cabinclass', cabinClass);
      params.append('childrenv2', children > 0 ? children.toString() : '');
      params.append('ref', 'home');
      params.append('rtn', '1');
      params.append('preferdirects', 'false');
      params.append('outboundaltsenabled', 'false');
      params.append('inboundaltsenabled', 'false');

      const fullUrl = `${baseUrl}?${params.toString()}`;

      window.open(fullUrl, '_blank');
      onClose();
  };

  return (
    <div className="fixed inset-0 z-[3000] bg-black/60 backdrop-blur-sm flex items-center justify-center p-4 animate-fadeIn">
        <div className="bg-white rounded-2xl w-full max-w-lg shadow-2xl border border-white/50 overflow-hidden">

            {/* Header */}
            <div className="bg-slate-900 text-white p-4 flex justify-between items-center">
                <div className="flex items-center gap-2">
                    <Plane className="w-5 h-5 text-indigo-400" />
                    <h2 className="font-bold text-lg">Book Your Flight</h2>
                </div>
                <button onClick={onClose} className="hover:bg-slate-700 p-1.5 rounded-full transition">
                    <X className="w-5 h-5" />
                </button>
            </div>

            <div className="p-6 space-y-5">

                {/* Route Section */}
                <div className="space-y-4">
                    <div className="grid grid-cols-2 gap-4">
                        {/* Origin */}
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">From</label>
                            <input 
                                type="text"
                                className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm font-semibold text-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={origin}
                                onChange={(e) => setOrigin(e.target.value)}
                                placeholder="City (e.g. KL)"
                            />
                            <div className="mt-1 flex items-center gap-2">
                                <span className="text-[10px] text-slate-400 font-bold">IATA CODE:</span>
                                <input 
                                    type="text" 
                                    className={`w-16 p-1 text-xs text-center font-mono font-bold border rounded uppercase ${originCode ? 'bg-indigo-50 text-indigo-700 border-indigo-200' : 'bg-red-50 text-red-500 border-red-200'}`}
                                    value={originCode}
                                    onChange={(e) => setOriginCode(e.target.value.toUpperCase())}
                                    placeholder="???"
                                    maxLength={4}
                                />
                            </div>
                        </div>

                        {/* Destination */}
                        <div>
                            <label className="block text-xs font-bold text-slate-500 uppercase mb-1">To</label>
                            <input 
                                type="text"
                                className="w-full p-2.5 bg-slate-50 border border-slate-200 rounded-lg text-sm font-semibold text-slate-800 focus:ring-2 focus:ring-indigo-500 outline-none"
                                value={destination}
                                onChange={(e) => setDestination(e.target.value)}
                                placeholder="City (e.g. Tokyo)"
                            />
                            <div className="mt-1 flex items-center gap-2">
                                <span className="text-[10px] text-slate-400 font-bold">IATA CODE:</span>
                                <input 
                                    type="text" 
                                    className={`w-16 p-1 text-xs text-center font-mono font-bold border rounded uppercase ${destCode ? 'bg-indigo-50 text-indigo-700 border-indigo-200' : 'bg-red-50 text-red-500 border-red-200'}`}
                                    value={destCode}
                                    onChange={(e) => setDestCode(e.target.value.toUpperCase())}
                                    placeholder="???"
                                    maxLength={4}
                                />
                            </div>
                        </div>
                    </div>
                </div>

                {/* Dates Section */}
                <div className="grid grid-cols-2 gap-4">
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1 flex items-center gap-1"><Calendar className="w-3 h-3"/> Depart</label>
                        <input 
                            type="date"
                            className="w-full p-2.5 bg-white border border-slate-200 rounded-lg text-sm text-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none"
                            value={departDate}
                            onChange={(e) => setDepartDate(e.target.value)}
                        />
                    </div>
                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-1 flex items-center gap-1"><Calendar className="w-3 h-3"/> Return</label>
                        <input 
                            type="date"
                            className="w-full p-2.5 bg-white border border-slate-200 rounded-lg text-sm text-slate-700 focus:ring-2 focus:ring-indigo-500 outline-none"
                            value={returnDate}
                            min={departDate}
                            onChange={(e) => setReturnDate(e.target.value)}
                        />
                    </div>
                </div>

                {/* Passengers & Class */}
                <div className="bg-slate-50 p-4 rounded-xl border border-slate-200 space-y-3">
                     <div className="flex justify-between items-center">
                        <label className="text-xs font-bold text-slate-500 uppercase flex items-center gap-1"><Users className="w-3 h-3"/> Passengers</label>
                        <div className="flex gap-4">
                            <div className="flex items-center gap-2">
                                <span className="text-xs text-slate-600">Adults</span>
                                <input type="number" min="1" max="9" value={adults} onChange={(e) => setAdults(parseInt(e.target.value))} className="w-12 p-1 text-center border rounded-md text-sm" />
                            </div>
                            <div className="flex items-center gap-2">
                                <span className="text-xs text-slate-600">Children</span>
                                <input type="number" min="0" max="9" value={children} onChange={(e) => setChildren(parseInt(e.target.value))} className="w-12 p-1 text-center border rounded-md text-sm" />
                            </div>
                        </div>
                     </div>

                     <div className="pt-2 border-t border-slate-200">
                        <label className="block text-xs font-bold text-slate-500 uppercase mb-2 flex items-center gap-1"><Briefcase className="w-3 h-3"/> Cabin Class</label>
                        <div className="flex gap-2">
                            {['economy', 'premiumeconomy', 'business', 'first'].map((cls) => (
                                <button
                                    key={cls}
                                    onClick={() => setCabinClass(cls)}
                                    className={`px-3 py-1.5 text-xs font-bold rounded-lg capitalize border transition ${cabinClass === cls ? 'bg-indigo-600 text-white border-indigo-600' : 'bg-white text-slate-600 border-slate-200 hover:bg-slate-100'}`}
                                >
                                    {cls === 'premiumeconomy' ? 'Prem. Econ' : cls}
                                </button>
                            ))}
                        </div>
                     </div>
                </div>

                <button 
                    onClick={handleSearch}
                    className="w-full bg-indigo-600 hover:bg-indigo-700 text-white font-bold py-3.5 rounded-xl shadow-lg shadow-indigo-200 transform hover:scale-[1.01] transition flex items-center justify-center gap-2"
                >
                    <Plane className="w-5 h-5" />
                    Search Flights on Skyscanner
                </button>
            </div>
        </div>
    </div>
  );
};

export default FlightBookingModal;

import React, { useState, useRef, useEffect } from 'react';
import { TripPlan, UserPreferences, Activity, ChatMessage } from '../types';
import Itinerary from './Itinerary';
import Map from './Map';
import ChatAssistant from './ChatAssistant';
import { chatWithAI } from '../services/geminiService';
import ComparisonModal from './ComparisonModal';
import PlaceDetailsModal from './PlaceDetailsModal';
import FlightBookingModal from './FlightBookingModal';
import AdUnlockModal from './AdUnlockModal'; 
import { GripVertical } from 'lucide-react';
import { CACHE_KEY_PLAN } from '../constants';

interface Props {
  initialPlan: TripPlan;
  preferences: UserPreferences;
  onNewTrip: () => void;
}

const Dashboard: React.FC<Props> = ({ initialPlan, preferences, onNewTrip }) => {
  const [plan, setPlan] = useState<TripPlan>(initialPlan);
  const [selectedDay, setSelectedDay] = useState<number | undefined>(undefined);
  const [isUpdating, setIsUpdating] = useState(false);
  const [mobileView, setMobileView] = useState<'list' | 'map'>('list');
  const [showComparison, setShowComparison] = useState(false);
  const [selectedActivity, setSelectedActivity] = useState<Activity | null>(null);
  const [isFlightModalOpen, setIsFlightModalOpen] = useState(false);
  const [isDevMode, setIsDevMode] = useState(false);

  // Chat State
  const [messages, setMessages] = useState<ChatMessage[]>([]);

  // Monetization / Limits State
  const [modCount, setModCount] = useState(0);
  const [compareCount, setCompareCount] = useState(0);
  const [showAd, setShowAd] = useState(false);
  const [pendingAction, setPendingAction] = useState<{ type: 'CHAT' | 'COMPARE', payload?: string } | null>(null);

  // Constants
  const FREE_MODIFICATION_LIMIT = 3; 
  const FREE_COMPARE_LIMIT = 1;

  // Resizable panel state
  const [leftPanelWidth, setLeftPanelWidth] = useState(35); 
  const [isDragging, setIsDragging] = useState(false);
  const containerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    setIsDevMode(localStorage.getItem('tripgenie_dev_mode') === 'true');
  }, []);

  const handleMouseDown = (e: React.MouseEvent) => {
    setIsDragging(true);
    e.preventDefault();
  };

  useEffect(() => {
    const handleMouseMove = (e: MouseEvent) => {
      if (!isDragging || !containerRef.current) return;
      const containerRect = containerRef.current.getBoundingClientRect();
      const newWidth = ((e.clientX - containerRect.left) / containerRect.width) * 100;
      if (newWidth > 20 && newWidth < 80) {
        setLeftPanelWidth(newWidth);
      }
    };
    const handleMouseUp = () => {
      setIsDragging(false);
    };
    if (isDragging) {
      document.addEventListener('mousemove', handleMouseMove);
      document.addEventListener('mouseup', handleMouseUp);
    }
    return () => {
      document.removeEventListener('mousemove', handleMouseMove);
      document.removeEventListener('mouseup', handleMouseUp);
    };
  }, [isDragging]);

  // --- Logic for Chat & Modifications ---
  const executeChat = async (userMessage: string) => {
    // 1. Add User Message
    const userMsgObj: ChatMessage = { id: Date.now().toString(), role: 'user', text: userMessage };
    setMessages(prev => [...prev, userMsgObj]);

    setIsUpdating(true);
    try {
      // 2. Call AI
      const response = await chatWithAI(plan, userMessage);

      // 3. Handle Response
      const aiMsgObj: ChatMessage = { 
          id: (Date.now() + 1).toString(), 
          role: 'model', 
          text: response.answer,
          isPlanUpdate: response.intent === 'modify'
      };
      setMessages(prev => [...prev, aiMsgObj]);

      // 4. Update Plan if intent was 'modify'
      if (response.intent === 'modify' && response.modified_plan) {
          setPlan(response.modified_plan);
          setModCount(prev => prev + 1);
          // Persist the modification to cache so it survives refresh/navigation
          localStorage.setItem(CACHE_KEY_PLAN, JSON.stringify(response.modified_plan));
      }
    } catch (e) {
      const errorMsg: ChatMessage = { id: Date.now().toString(), role: 'model', text: "Sorry, I encountered an error. Please try again." };
      setMessages(prev => [...prev, errorMsg]);
    } finally {
      setIsUpdating(false);
    }
  };

  const handleChatRequest = (message: string) => {
      // Check limits
      if (!isDevMode && modCount >= FREE_MODIFICATION_LIMIT) {
          setPendingAction({ type: 'CHAT', payload: message });
          setShowAd(true);
      } else {
          executeChat(message);
      }
  };

  // --- Logic for Comparison ---
  const handleCompareRequest = () => {
      if (!isDevMode && compareCount >= FREE_COMPARE_LIMIT) {
          setPendingAction({ type: 'COMPARE' });
          setShowAd(true);
      } else {
          setCompareCount(prev => prev + 1);
          setShowComparison(true);
      }
  };

  // --- Ad Reward Handler ---
  const handleAdReward = () => {
      setShowAd(false);

      if (pendingAction?.type === 'CHAT' && pendingAction.payload) {
          setModCount(0); // Reset count
          executeChat(pendingAction.payload);
      } else if (pendingAction?.type === 'COMPARE') {
          setCompareCount(prev => prev + 1);
          setShowComparison(true);
      }
      setPendingAction(null);
  };

  const handleDayClick = (day: number | undefined) => {
      setSelectedDay(day);
      if (window.innerWidth < 1024) {
          setMobileView('map');
      }
  };

  return (
    // Clean full height layout, no fixed hacks needed as Navbar is removed via parent
    <div ref={containerRef} className="flex h-full w-full overflow-hidden bg-gradient-to-br from-indigo-50 via-purple-50 to-pink-50">

      {showAd && (
          <AdUnlockModal 
            duration={15}
            onClose={() => setShowAd(false)}
            onReward={handleAdReward}
            title={pendingAction?.type === 'CHAT' ? "Refill AI Credits" : "Unlock Comparison"}
            message={pendingAction?.type === 'CHAT' 
                ? "You've used your free AI interactions. Watch an ad to continue chatting." 
                : "Watch a short ad to compare your trip."}
          />
      )}

      {/* Left Panel */}
      <div 
        className={`${mobileView === 'list' ? 'block' : 'hidden'} lg:block h-full border-r border-slate-200 relative bg-white flex flex-col z-20 shadow-xl lg:shadow-none transition-all duration-75 ease-linear`}
        style={{ width: window.innerWidth >= 1024 ? `${leftPanelWidth}%` : '100%' }}
      >
        <Itinerary 
            tripPlan={plan} 
            onDayClick={handleDayClick} 
            onNewTrip={onNewTrip} 
            onShowMap={() => setMobileView('map')}
            onCompare={handleCompareRequest} 
            onPlaceClick={(activity) => setSelectedActivity(activity)}
        />

        <div className="absolute bottom-6 left-1/2 transform -translate-x-1/2 z-30 lg:bottom-8 w-max">
            <button 
                onClick={() => setIsFlightModalOpen(true)}
                className="bg-slate-900 text-white font-bold py-3 px-8 rounded-full shadow-xl hover:scale-105 transition transform flex items-center gap-2 border border-slate-700"
            >
                Book Flights ✈️
            </button>
        </div>
      </div>

      {/* Resize Handle */}
      <div 
        className="hidden lg:flex w-4 hover:w-5 cursor-col-resize items-center justify-center bg-slate-50 border-l border-r border-slate-200 absolute top-0 bottom-0 z-50 group transition-all"
        style={{ left: `${leftPanelWidth}%`, transform: 'translateX(-50%)' }}
        onMouseDown={handleMouseDown}
      >
        <div className="h-8 w-1 flex flex-col justify-center gap-0.5">
             <GripVertical className="w-4 h-4 text-slate-300 group-hover:text-indigo-400" />
        </div>
      </div>

      {/* Right Panel */}
      <div 
        className={`${mobileView === 'map' ? 'block' : 'hidden'} lg:block h-full relative z-10 bg-slate-50`}
        style={{ width: window.innerWidth >= 1024 ? `${100 - leftPanelWidth}%` : '100%' }}
      >
        <Map 
            tripPlan={plan} 
            selectedDay={selectedDay} 
            onBackToList={() => setMobileView('list')}
        />
      </div>

      {/* Chat Overlay */}
      <ChatAssistant 
        messages={messages} 
        onSendMessage={handleChatRequest} 
        isUpdating={isUpdating} 
      />

      {showComparison && (
          <ComparisonModal 
            currentPlan={plan} 
            preferences={preferences} 
            onClose={() => setShowComparison(false)} 
          />
      )}

      {selectedActivity && (
          <PlaceDetailsModal 
            activity={selectedActivity} 
            onClose={() => setSelectedActivity(null)} 
          />
      )}

      {isFlightModalOpen && (
          <FlightBookingModal 
             preferences={preferences}
             onClose={() => setIsFlightModalOpen(false)}
          />
      )}
    </div>
  );
};

export default Dashboard;

import { GoogleGenAI, Type } from "@google/genai";
import { TripPlan, UserPreferences, ChatResponse } from "../types";
import { MOCK_TRIP_PLAN } from "../constants"; // Import Mock Data
import emailjs from '@emailjs/browser';

// Define the response schema for Gemini (Trip Plan)
const tripSchema = {
  type: Type.OBJECT,
  properties: {
    trip_summary: { type: Type.STRING, description: "A catchy summary of the trip" },
    estimated_budget: { type: Type.STRING, description: "Total estimated cost for the trip (Food, Transport, Tickets ONLY). EXCLUDE flights, accommodation, and shopping. Display in two currencies." },
    budget_breakdown: { type: Type.STRING, description: "Detailed explanation of what the estimated_budget covers. Explicitly mention the buffer amount added for unlisted meals, snacks, bottled water, and casual transport." },
    suggested_dates: { type: Type.STRING, description: "Specific dates (e.g. 'April 5 - April 10') if user only gave duration, or user's dates." },
    date_reasoning: { type: Type.STRING, description: "Why these dates? (e.g. 'Cherry blossom season', 'Low crowds')" },
    suggested_hotels: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          description: { type: Type.STRING },
          price_range: { type: Type.STRING, description: "e.g. $100-150/night" }
        }
      },
      description: "Suggest 2-3 hotels if user didn't specify one."
    },
    warnings: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Safety or tourist trap warnings" },
    packing_list: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Essential items to pack" },
    weather_forecast: { type: Type.STRING, description: "Expected weather and clothing advice" },
    transport_advice: { type: Type.STRING, description: "Best way to get around (cards, apps, etc)" },
    flight_delay_backup: { type: Type.STRING, description: "A contingency plan if flights are delayed" },
    days: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day_number: { type: Type.INTEGER },
          theme: { type: Type.STRING },
          activities: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                place_name: { type: Type.STRING },
                action: { type: Type.STRING, description: "What to do here" },
                description: { type: Type.STRING, description: "2 sentences describing why this place is interesting for the details view." },
                latitude: { type: Type.NUMBER },
                longitude: { type: Type.NUMBER },
                transport_tip: { type: Type.STRING },
                type: { type: Type.STRING, enum: ["sightseeing", "food", "transport", "hotel", "other"] },
                cost_estimate: { type: Type.STRING }
              },
              required: ["place_name", "action", "latitude", "longitude", "type"]
            }
          }
        },
        required: ["day_number", "theme", "activities"]
      }
    }
  },
  required: ["trip_summary", "estimated_budget", "budget_breakdown", "days", "warnings", "packing_list", "transport_advice"]
};

// Define Schema for Hybrid Chat (Response can be text OR a modified plan)
const chatSchema = {
    type: Type.OBJECT,
    properties: {
        intent: { 
            type: Type.STRING, 
            enum: ["chat", "modify"],
            description: "Determine if the user is asking a general question ('chat') or wants to change the itinerary ('modify')." 
        },
        answer: { 
            type: Type.STRING, 
            description: "The text response to the user. If 'modify', explain what you changed." 
        },
        modified_plan: tripSchema // Embed the trip schema here
    },
    required: ["intent", "answer"]
};

