  });
  const [showAdvanced, setShowAdvanced] = useState(false);
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [currentInput, setCurrentInput] = useState('');
  const [destinations, setDestinations] = useState<string[]>([]);
  const [showDatePicker, setShowDatePicker] = useState(false);
  const [dateRange, setDateRange] = useState({ start: '', end: '' });

  const location = useLocation();
  const t = UI_TEXT[formData.language] || UI_TEXT['English'];
  const marketing = getMarketingCopy(formData.language);

  useEffect(() => {
    if (location.state && (location.state as any).autoFillDestination) {
        const destName = (location.state as any).autoFillDestination;
        setDestinations(prev => {
            if (prev.includes(destName)) return prev;
            const newDestinations = [...prev, destName];
            setFormData(prevForm => ({ ...prevForm, destination: newDestinations.join(', ') }));
            return newDestinations;
        });
        window.history.replaceState({}, ''); 
    }
  }, []);

  useEffect(() => {
    if (dateRange.start && dateRange.end) {
        const start = new Date(dateRange.start);
        const end = new Date(dateRange.end);
        const diffTime = end.getTime() - start.getTime();
        const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)) + 1;
        if (diffDays > 0) {
            setFormData(prev => ({ ...prev, duration: `${diffDays} Days (${dateRange.start} to ${dateRange.end})` }));
        }
    }
  }, [dateRange]);

  const handleDestinationInput = (e: React.ChangeEvent<HTMLInputElement>) => {
      const val = e.target.value;
      setCurrentInput(val);
      const lowerVal = val.toLowerCase().trim();
      if (lowerVal.length > 2) {
         const matches = new Set<string>();
         Object.entries(POPULAR_DESTINATIONS).forEach(([country, cities]) => {
             if (country.includes(lowerVal)) cities.forEach(c => matches.add(c));
             cities.forEach(city => { if (city.toLowerCase().includes(lowerVal)) matches.add(city); });
         });
         setSuggestions(Array.from(matches).slice(0, 6));
      } else { setSuggestions([]); }
  };

  const addDestination = (place: string) => {
      const trimmed = place.trim();
      if (trimmed && !destinations.includes(trimmed)) {
          const newDests = [...destinations, trimmed];
          setDestinations(newDests);
          setFormData({ ...formData, destination: newDests.join(', ') });
      }
      setCurrentInput('');
      setSuggestions([]);
  };

  const removeDestination = (placeToRemove: string) => {
      const newDests = destinations.filter(d => d !== placeToRemove);
      setDestinations(newDests);
      setFormData({ ...formData, destination: newDests.join(', ') });
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    let finalDests = [...destinations];
    if (currentInput.trim()) finalDests.push(currentInput.trim());
    if (finalDests.length > 0 && formData.duration) onSubmit({ ...formData, destination: finalDests.join(', ') });
  };

  return (
    <div className="w-full flex-grow flex flex-col items-center justify-start pt-8 pb-10" dir={formData.language === 'Arabic' ? 'rtl' : 'ltr'}>
      <div className="max-w-xl w-full bg-white/80 backdrop-blur-xl rounded-3xl shadow-xl shadow-indigo-100/50 overflow-hidden mb-12 flex-shrink-0 border border-white/60 relative z-10 mx-4">
            <div className="p-8 text-center border-b border-white/50 relative">
                <div className="w-16 h-16 bg-gradient-to-tr from-indigo-500 to-purple-500 rounded-2xl flex items-center justify-center mx-auto mb-4 shadow-lg shadow-indigo-200 transform rotate-3">
                     <Plane className="w-8 h-8 text-white" /> 
                </div>
                <h1 className="text-2xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-indigo-600 to-purple-600 mb-2 tracking-tight">{marketing.heroTitle}</h1>
                <p className="text-slate-500 text-sm leading-relaxed max-w-sm mx-auto">{marketing.heroSubtitle}</p>
            </div>

            {savedTripDest && onResume && (
                <div className="px-6 pt-6">
                    <div className="bg-indigo-50 border border-indigo-100 rounded-2xl p-4 flex items-center justify-between shadow-sm relative overflow-hidden group">
                        <div className="flex items-center gap-3 relative z-10">
                            <History className="w-5 h-5 text-indigo-600" />
                            <p className="text-sm font-bold text-indigo-900 leading-tight">Resume trip to {savedTripDest}?</p>
                        </div>
                        <button onClick={onResume} className="bg-indigo-600 text-white text-xs font-bold px-4 py-2.5 rounded-xl">Resume</button>
                    </div>
                </div>
            )}

            <form onSubmit={handleSubmit} className="p-6 space-y-6">
                <div>
                    <label className="block text-xs font-bold text-slate-500 uppercase tracking-wider mb-2">{t.whereLabel}</label>
                    <div className="flex flex-wrap gap-2 mb-3">
                        {destinations.map(dest => (
                            <span key={dest} className="bg-indigo-50 text-indigo-700 px-3 py-1 rounded-full text-sm font-medium flex items-center gap-1 border border-indigo-100">
                                {dest} <button type="button" onClick={() => removeDestination(dest)}><X className="w-3 h-3" /></button>
                            </span>
                        ))}
                    </div>
                    <div className="relative group">
                        <MapPin className="absolute top-3.5 left-4 text-slate-400 w-5 h-5" />
                        <input type="text" placeholder={t.wherePlaceholder} className="w-full py-3 bg-white/70 border border-slate-200 rounded-2xl pl-12 pr-4 outline-none" value={currentInput} onChange={handleDestinationInput} onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), addDestination(currentInput))} />
                    </div>
                </div>

                <div className="grid grid-cols-2 gap-4">
                    <div className="relative">
                        <PlaneTakeoff className="absolute top-3.5 left-4 text-slate-400 w-5 h-5" />
                        <input type="text" placeholder={t.departPlaceholder} className="w-full py-3 bg-white/70 border border-slate-200 rounded-2xl pl-12 pr-4 outline-none" value={formData.departFrom || ''} onChange={(e) => setFormData({ ...formData, departFrom: e.target.value })} />
