    flight_delay_backup: { type: Type.STRING },
    days: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day_number: { type: Type.INTEGER },
          theme: { type: Type.STRING },
          activities: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                place_name: { type: Type.STRING },
                action: { type: Type.STRING },
                description: { type: Type.STRING },
                latitude: { type: Type.NUMBER },
                longitude: { type: Type.NUMBER },
                transport_tip: { type: Type.STRING },
                type: { type: Type.STRING, enum: ["sightseeing", "food", "transport", "hotel", "other"] },
                cost_estimate: { type: Type.STRING }
              },
              required: ["place_name", "action", "latitude", "longitude", "type"]
            }
          }
        },
        required: ["day_number", "theme", "activities"]
      }
    }
  },
  required: ["trip_summary", "estimated_budget", "budget_breakdown", "days", "warnings", "packing_list", "transport_advice"]
};

const chatSchema = {
    type: Type.OBJECT,
    properties: {
        intent: { type: Type.STRING, enum: ["chat", "modify"] },
        answer: { type: Type.STRING },
        modified_plan: tripSchema
    },
    required: ["intent", "answer"]
};

// --- API CLIENT ---
const getAiClient = () => {
    if (!process.env.API_KEY) throw new Error("API Key is missing.");
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
};

// --- ACTIONS ---
export const generateTripPlan = async (prefs: UserPreferences): Promise<TripPlan> => {
  if (typeof window !== 'undefined' && localStorage.getItem('tripgenie_dev_mode') === 'true') {
      return MOCK_TRIP_PLAN;
  }

  const ai = getAiClient();
  const complex = isComplexRequest(prefs);
  const selectedModel = complex ? MODEL_PRO : MODEL_FLASH;

  const prompt = `
    Act as AriaTrip AI, a local travel expert. 
    User Request: ${JSON.stringify(prefs)}

    Generate a logical, day-by-day itinerary clustered by neighborhood to avoid backtracking. 
    Budget Rules: Economy = hostels/street food, Standard = mid-range, Luxury = 5-star/fine dining.
    Currency: Show all costs in Destination currency AND Home currency (e.g., 10k JPY (~$70 USD)).
    All text must be in ${prefs.language}.
  `;

  try {
    const response = await ai.models.generateContent({
      model: selectedModel,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: tripSchema,
        temperature: complex ? 0.5 : 0.3,
      },
    });

    if (!response.text) throw new Error("No response from AI");
    return JSON.parse(response.text) as TripPlan;
  } catch (error: any) {
      console.error("TripGen Error:", error);
      if (error.toString().includes("429")) return MOCK_TRIP_PLAN;
      throw error;
  }
};

export const chatWithAI = async (currentPlan: TripPlan, userMessage: string): Promise<ChatResponse> => {
    const ai = getAiClient();
    const complex = isComplexChat(userMessage);
    const selectedModel = complex ? MODEL_PRO : MODEL_FLASH;

    const prompt = `
    You are AriaTrip AI. Current Plan: ${JSON.stringify(currentPlan)}
    User Message: "${userMessage}"

    Intent: "chat" (general questions) or "modify" (change the plan).
    Maintain geospatial clustering and dual-currency formats.
    `;

    try {
        const response = await ai.models.generateContent({
            model: selectedModel,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: chatSchema,
                temperature: 0.5,
            },
        });
        if (!response.text) throw new Error("Empty AI response");
        return JSON.parse(response.text) as ChatResponse;
    } catch (error: any) {
        throw error;
    }
};

export const generateStandardTour = async (prefs: UserPreferences): Promise<TripPlan> => {
    const ai = getAiClient();
    const prompt = `Create a generic tourist-trap group tour for ${prefs.destination} (${prefs.duration}).`;
    try {
        const response = await ai.models.generateContent({
            model: MODEL_FLASH,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: tripSchema,
                temperature: 0.2,
            },
        });
        return JSON.parse(response.text!) as TripPlan;
    } catch (e) {
        return MOCK_TRIP_PLAN;
    }
};

