import { GoogleGenAI, Type } from "@google/genai";
import { TripPlan, UserPreferences, ChatResponse } from "../types";
import { MOCK_TRIP_PLAN } from "../constants";
import emailjs from '@emailjs/browser';

// --- CONFIGURATION ---
const MODEL_FLASH = "gemini-3-flash-preview";
const MODEL_PRO = "gemini-3-pro-preview";

export const isComplexRequest = (prefs: UserPreferences): boolean => {
    const cityCount = prefs.destination.split(',').length;
    const dayMatch = prefs.duration.match(/\d+/);
    const dayCount = dayMatch ? parseInt(dayMatch[0]) : 0;
    const constraintLength = prefs.constraints?.length || 0;
    return cityCount > 2 || dayCount > 8 || constraintLength > 150 || (prefs.style?.length || 0) > 5;
};

export const isComplexChat = (message: string): boolean => {
    const complexKeywords = ['restructure', 'optimize', 'compare', 'efficiency', 'accessibility', 'medical', 'advanced', 'rewrite'];
    return message.length > 200 || complexKeywords.some(kw => message.toLowerCase().includes(kw));
};

const tripSchema = {
  type: Type.OBJECT,
  properties: {
    trip_summary: { type: Type.STRING },
    estimated_budget: { type: Type.STRING },
    budget_breakdown: { type: Type.STRING },
    suggested_dates: { type: Type.STRING },
    date_reasoning: { type: Type.STRING },
    suggested_hotels: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          name: { type: Type.STRING },
          description: { type: Type.STRING },
          price_range: { type: Type.STRING }
        }
      }
    },
    warnings: { type: Type.ARRAY, items: { type: Type.STRING } },
    packing_list: { type: Type.ARRAY, items: { type: Type.STRING } },
    weather_forecast: { type: Type.STRING },
    transport_advice: { type: Type.STRING },
    flight_delay_backup: { type: Type.STRING },
    days: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          day_number: { type: Type.INTEGER },
          theme: { type: Type.STRING },
          activities: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                place_name: { type: Type.STRING },
                action: { type: Type.STRING },
                description: { type: Type.STRING },
                latitude: { type: Type.NUMBER },
                longitude: { type: Type.NUMBER },
                transport_tip: { type: Type.STRING },
                type: { type: Type.STRING, enum: ["sightseeing", "food", "transport", "hotel", "other"] },
                cost_estimate: { type: Type.STRING }
              },
              required: ["place_name", "action", "latitude", "longitude", "type"]
            }
          }
        },
        required: ["day_number", "theme", "activities"]
      }
    }
  },
  required: ["trip_summary", "estimated_budget", "budget_breakdown", "days", "warnings", "packing_list", "transport_advice"]
};

const chatSchema = {
    type: Type.OBJECT,
    properties: {
        intent: { type: Type.STRING, enum: ["chat", "modify"] },
        answer: { type: Type.STRING },
        modified_plan: tripSchema
    },
    required: ["intent", "answer"]
};

export const generateTripPlan = async (prefs: UserPreferences): Promise<TripPlan> => {
  if (typeof window !== 'undefined' && localStorage.getItem('tripgenie_dev_mode') === 'true') {
      return MOCK_TRIP_PLAN;
  }
  // Fix: Strictly use process.env.API_KEY as per GenAI guidelines
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
  const complex = isComplexRequest(prefs);
  const selectedModel = complex ? MODEL_PRO : MODEL_FLASH;

  const prompt = `Act as AriaTrip AI travel planner. Request: ${JSON.stringify(prefs)}. Generate JSON. Language: ${prefs.language}. Budget in Local (~Home).`;

  try {
    const response = await ai.models.generateContent({
      model: selectedModel,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: tripSchema,
        temperature: complex ? 0.5 : 0.3,
      },
    });
    // Fix: Access .text property directly (not as a method)
    return JSON.parse(response.text || "{}") as TripPlan;
  } catch (error: any) {
    if (error.toString().includes("429")) return MOCK_TRIP_PLAN;
    throw error;
  }
};

export const chatWithAI = async (currentPlan: TripPlan, userMessage: string): Promise<ChatResponse> => {
    // Fix: Strictly use process.env.API_KEY
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const complex = isComplexChat(userMessage);
    const selectedModel = complex ? MODEL_PRO : MODEL_FLASH;
    const prompt = `AriaTrip AI Assistant. Plan: ${JSON.stringify(currentPlan)}. Message: ${userMessage}. Return intent, answer, modified_plan.`;
    try {
        const response = await ai.models.generateContent({
            model: selectedModel,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: chatSchema,
                temperature: 0.5,
            },
        });
        // Fix: Access .text property directly
        return JSON.parse(response.text || "{}") as ChatResponse;
    } catch (error: any) {
        throw error;
    }
};

export const generateStandardTour = async (prefs: UserPreferences): Promise<TripPlan> => {
    // Fix: Strictly use process.env.API_KEY
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `Generic tourist tour for ${prefs.destination}.`;
    try {
        const response = await ai.models.generateContent({
            model: MODEL_FLASH,
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: tripSchema,
                temperature: 0.2,
            },
        });
        // Fix: Access .text property directly
        return JSON.parse(response.text || "{}") as TripPlan;
    } catch (e) {
        return MOCK_TRIP_PLAN;
    }
};

