    e.preventDefault();
    const finalDest = destinations.length > 0 ? destinations.join(', ') : destInput;
    if (!finalDest) return;

    onSubmit({
      destination: finalDest,
      departFrom,
      duration,
      layover,
      hotel,
      style: selectedStyles,
      constraints,
      language: lang,
      budget,
      pacing,
      transportMode
